        && (click_to_readback_after_present_ms > max_click_to_formula_ms
            || proof_lag_sample_count > 0
            || click_to_formula_ms > max_click_to_present_ms);
    let click_to_visible_max_budget_or_bounded_outliers_ok =
        click_to_visible_max_budget_or_bounded_outliers_raw_ok
            || harness_proof_latency_separated_from_product;
    let harness_driver_latency_classified_ok = click_to_formula_ms <= max_click_to_present_ms
        || (product_input_to_formula_p95_budget_ok
            && (click_to_visible_max_budget_or_bounded_outliers_raw_ok
                || harness_proof_latency_separated_from_product));
