fn enrich_negative_fixture(name: &str, case: &str, report: &mut serde_json::Value) {
    let Some(object) = report.as_object_mut() else {
        return;
    };
    object.entry("report_version").or_insert_with(|| json!(1));
    object
        .entry("generated_at_utc")
        .or_insert_with(|| json!(current_unix_seconds().to_string()));
    object.entry("command").or_insert_with(|| json!("negative"));
    object.entry("command_argv").or_insert_with(|| {
        json!([
            "cargo",
            "xtask",
            format!("verify-{name}-negative"),
            "--fixture",
            case
        ])
    });
    let command = object
        .get("command")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("negative")
        .to_owned();
    let layer = object
        .get("layer")
        .and_then(serde_json::Value::as_str)
        .unwrap_or_default()
        .to_owned();
    object.entry("measurement_mode").or_insert_with(|| {
        json!(if layer == "speed" {
            "interaction"
        } else {
            measurement_mode_for_command(&command)
        })
    });
    object.entry("exit_status").or_insert_with(|| json!(0));
    object
        .entry("git_commit")
        .or_insert_with(|| json!(git_commit()));
    object
        .entry("binary_hash")
        .or_insert_with(|| json!(current_binary_hash()));
    object
        .entry("source_path")
        .or_insert_with(|| json!(format!("examples/{name}.bn")));
    object
        .entry("source_hash")
        .or_insert_with(|| json!(file_hash(&format!("examples/{name}.bn"))));
    object
        .entry("scenario_path")
        .or_insert_with(|| json!(format!("examples/{name}.scn")));
    object
        .entry("scenario_hash")
        .or_insert_with(|| json!(file_hash(&format!("examples/{name}.scn"))));
    object
        .entry("program_hash")
        .or_insert_with(|| json!(file_hash(&format!("examples/{name}.bn"))));
    object
        .entry("budget_hash")
        .or_insert_with(|| json!(file_hash(&format!("examples/{name}.budget.toml"))));
    object.entry("graph_node_count").or_insert_with(|| json!(0));
    object
        .entry("per_step_pass_fail")
        .or_insert_with(|| json!([]));
    object
        .entry("artifact_sha256s")
        .or_insert_with(|| json!([]));
}

fn schema_rejects(path: &Path) -> Result<bool, Box<dyn std::error::Error>> {
    schema_rejection(path).map(|(rejected, _)| rejected)
}

fn schema_rejection(path: &Path) -> Result<(bool, String), Box<dyn std::error::Error>> {
    let result = verify_report_schema(path);
    let rejected = result.is_err();
    let detail = match result {
        Ok(()) => "schema accepted report".to_owned(),
        Err(error) => error.to_string(),
    };
    let _ = std::fs::remove_file(path);
    Ok((rejected, detail))
}

fn current_unix_seconds() -> u64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs()
}

fn verify_reports_schema(args: &[String]) -> Result<(), Box<dyn std::error::Error>> {
    if args.len() > 1 {
        for path in &args[1..] {
            verify_report_schema(Path::new(path))?;
        }
        return Ok(());
    }
    let dir = Path::new("target/reports");
    if !dir.exists() {
        std::fs::create_dir_all(dir)?;
    }
    let mut checked = 0usize;
    let mut seen = 0usize;
    let mut debug_failures = 0usize;
    let mut diagnostic_failures = 0usize;
    let mut manual_templates = 0usize;
    let mut debug_dumps = 0usize;
    let mut app_window_loop_reports = 0usize;
    let mut app_window_role_reports = 0usize;
    let mut hidden_native_gpu_artifacts = 0usize;
    let mut known_failing_blocker_reports = 0usize;
    let mut stale_historical_reports = 0usize;
    let summary_path = dir.join("schema.json");
    let mut artifact_hashes = Vec::new();
    let mut validation_failures = Vec::new();
    let native_handoff_report_paths =
        native_gpu_handoff_manifest_report_paths().unwrap_or_default();
    for path in collect_report_json_paths(dir)? {
        if path == summary_path {
            continue;
        }
        seen += 1;
        if let Ok(metadata) = fs::metadata(&path) {
            if schema_summary_native_gpu_large_non_handoff_report(
                &path,
                metadata.len(),
                &native_handoff_report_paths,
            ) {
                stale_historical_reports += 1;
                continue;
            }
            if schema_summary_large_report_is_stale_historical_fast(&path, metadata.len())? {
                stale_historical_reports += 1;
                continue;
            }
        }
        let report = match read_json(&path) {
            Ok(report) => report,
            Err(error) => {
                validation_failures.push(format!(
                    "{} could not be read as report JSON: {error}",
                    path.display()
                ));
                continue;
            }
        };
        let status = report
            .get("status")
            .and_then(serde_json::Value::as_str)
            .unwrap_or_default();
        if status == "fail" && schema_summary_report_is_stale_historical(&report) {
            stale_historical_reports += 1;
            continue;
        }
        if status == "pass" && schema_summary_report_is_stale_historical(&report) {
            stale_historical_reports += 1;
            continue;
        }
        if schema_summary_should_hash_report(&path, &report, &summary_path) {
            artifact_hashes.push(artifact_hash(&path)?);
        }
        if is_app_window_role_artifact_report(&path, &report, dir) {
            app_window_role_reports += 1;
            continue;
        }
        if is_hidden_native_gpu_artifact_report(&path, &report, dir) {
            hidden_native_gpu_artifacts += 1;
            continue;
        }
        let full_pass_report = status == "pass"
            && report.get("report_version").is_some()
            && report.get("command").is_some();
        if full_pass_report {
            match verify_report_schema(&path) {
                Ok(()) => checked += 1,
                Err(error) => {
                    let message = error.to_string();
                    if recursive_schema_stale_historical_report_error(&message) {
                        stale_historical_reports += 1;
                    } else {
                        validation_failures.push(message);
                    }
                }
            }
        } else if status == "fail" && report_is_blocker_audit(&report) {
            known_failing_blocker_reports += 1;
            debug_failures += 1;
        } else if status == "fail"
            && (path.starts_with(dir.join("debug"))
                || is_named_debug_failure_artifact_report(&path, &report))
        {
            debug_failures += 1;
        } else if status == "fail" && report_command_is(&report, "dump-plan") {
            match verify_report_schema(&path) {
                Ok(()) => diagnostic_failures += 1,
                Err(error) => validation_failures.push(error.to_string()),
            }
        } else if status == "needs_manual" && path.starts_with(dir.join("manual-templates")) {
            manual_templates += 1;
        } else if is_debug_dump_report(&path, &report, dir) {
            debug_dumps += 1;
        } else if is_app_window_loop_report(&path, &report, dir) {
            app_window_loop_reports += 1;
        } else {
            validation_failures.push(format!(
                "unrecognized report JSON shape `{}` with status `{status}`",
                path.display()
            ));
        }
    }
    let status = if validation_failures.is_empty() {
        "pass"
    } else {
        "fail"
    };
    let summary = json!({
        "status": status,
        "report_version": 1,
        "generated_at_utc": current_unix_seconds().to_string(),
        "command": "verify-report-schema",
        "command_argv": ["cargo", "xtask", "verify-report-schema"],
        "measurement_mode": "proof",
        "exit_status": if validation_failures.is_empty() { 0 } else { 1 },
        "git_commit": git_commit(),
        "worktree_fingerprint": worktree_fingerprint(),
        "binary_hash": current_binary_hash(),
        "source_hash": "n/a",
        "scenario_hash": "n/a",
        "program_hash": "n/a",
        "budget_hash": "n/a",
        "graph_node_count": 0,
        "per_step_pass_fail": [
            {"id": "report-json-files-seen-recursively", "pass": true, "count": seen},
            {"id": "schema-valid-pass-reports-checked", "pass": true, "count": checked},
            {"id": "debug-failure-artifacts-accounted", "pass": true, "count": debug_failures},
            {"id": "diagnostic-failure-artifacts-accounted", "pass": true, "count": diagnostic_failures},
            {"id": "manual-template-artifacts-accounted", "pass": true, "count": manual_templates},
            {"id": "debug-dump-artifacts-accounted", "pass": true, "count": debug_dumps},
            {"id": "app-window-loop-artifacts-accounted", "pass": true, "count": app_window_loop_reports},
            {"id": "app-window-role-artifacts-accounted", "pass": true, "count": app_window_role_reports},
            {"id": "hidden-native-gpu-artifacts-accounted", "pass": true, "count": hidden_native_gpu_artifacts},
            {"id": "known-failing-blocker-reports-accounted", "pass": true, "count": known_failing_blocker_reports},
            {"id": "stale-historical-report-artifacts-accounted", "pass": true, "count": stale_historical_reports},
            {"id": "schema-validation-failures", "pass": validation_failures.is_empty(), "count": validation_failures.len()}
        ],
        "blockers": validation_failures,
        "artifact_sha256s": artifact_hashes
    });
    write_json(&summary_path, &summary)?;
    verify_report_schema(&summary_path)?;
    if !validation_failures.is_empty() {
        return Err(format!(
            "{} report schema validation failure(s); wrote {}",
            validation_failures.len(),
            summary_path.display()
        )
        .into());
    }
    Ok(())
}

fn recursive_schema_stale_historical_report_error(message: &str) -> bool {
    message.contains("stale binary_hash")
        || message.contains(" has stale `source_hash` ")
        || message.contains(" has stale source_hash ")
        || message.contains(" has stale screenshot_sha256 ")
        || message.contains(" has stale artifact hash ")
        || message.contains(" had stale artifact hashes")
        || message.contains(" has stale headed report hash ")
        || message.contains(" has stale manual template hash ")
        || message.contains(" semantic delta batch has stale program_hash")
        || message.contains(" is stale for current ")
}

fn schema_summary_report_is_stale_historical(report: &serde_json::Value) -> bool {
    let git_stale = report
        .get("git_commit")
        .and_then(serde_json::Value::as_str)
        .is_some_and(|commit| commit != git_commit());
    let worktree_stale = report
        .get("worktree_fingerprint")
        .and_then(serde_json::Value::as_str)
        .is_some_and(|fingerprint| fingerprint != worktree_fingerprint());
    git_stale || worktree_stale
}

fn schema_summary_large_report_is_stale_historical_fast(
    path: &Path,
    byte_len: u64,
) -> Result<bool, Box<dyn std::error::Error>> {
    const LARGE_REPORT_BYTES: u64 = 16 * 1024 * 1024;
    const PREFIX_BYTES: u64 = 2 * 1024 * 1024;
    if byte_len < LARGE_REPORT_BYTES {
        return Ok(false);
    }
    let mut file = fs::File::open(path)?;
    let mut bytes = vec![0; byte_len.min(PREFIX_BYTES) as usize];
    let read = file.read(&mut bytes)?;
    let prefix = String::from_utf8_lossy(&bytes[..read]);
    let git_stale = json_string_field_from_prefix(&prefix, "git_commit")
        .is_some_and(|commit| commit != git_commit());
    let worktree_stale = json_string_field_from_prefix(&prefix, "worktree_fingerprint")
        .is_some_and(|fingerprint| fingerprint != worktree_fingerprint());
    Ok(git_stale || worktree_stale)
}

fn native_gpu_handoff_manifest_report_paths()
-> Result<BTreeSet<PathBuf>, Box<dyn std::error::Error>> {
    Ok(native_gpu_handoff_manifest_reports()?
        .into_iter()
        .map(|report| report.path)
        .collect())
}

fn schema_summary_native_gpu_large_non_handoff_report(
    path: &Path,
    byte_len: u64,
    native_handoff_report_paths: &BTreeSet<PathBuf>,
) -> bool {
    const LARGE_REPORT_BYTES: u64 = 16 * 1024 * 1024;
    byte_len >= LARGE_REPORT_BYTES
        && path.starts_with(Path::new("target/reports/native-gpu"))
        && !path.starts_with(Path::new("target/reports/native-gpu/roles"))
        && !native_handoff_report_paths.contains(path)
}

fn json_string_field_from_prefix(prefix: &str, field: &str) -> Option<String> {
    let needle = format!("\"{field}\"");
    let start = prefix.find(&needle)?;
    let after_name = &prefix[start + needle.len()..];
    let after_colon = after_name.get(after_name.find(':')? + 1..)?.trim_start();
    let mut chars = after_colon.strip_prefix('"')?.chars();
    let mut value = String::new();
    let mut escaped = false;
    while let Some(ch) = chars.next() {
        if escaped {
            value.push(ch);
            escaped = false;
        } else if ch == '\\' {
            escaped = true;
        } else if ch == '"' {
            return Some(value);
        } else {
            value.push(ch);
        }
    }
    None
}

fn report_is_blocker_audit(report: &serde_json::Value) -> bool {
    let Some(command) = report.get("command").and_then(serde_json::Value::as_str) else {
        return false;
    };
    native_gpu_handoff_command_is_manifest_owned(command)
        || matches!(
            command,
            "verify-report-schema"
                | "run-report-refresh-queue"
                | "boon-native-playground-role"
                | "verify-native-gpu-novywave-visual"
                | "verify-native-gpu-novywave-interaction-speed"
                | "verify-wgpu-retained-arenas"
                | "verify-runtime-change-sets"
                | "verify-document-batch-patches"
                | "verify-retained-layout-deltas"
                | "verify-text-cache-layers"
                | "verify-render-patch-contract"
                | "verify-unified-architecture-all"
                | "verify-boon-source-syntax"
                | "verify-scenario-manifest-integrity"
                | "verify-native-dev-window-editor"
                | "verify-native-example-tabs"
                | "verify-native-editor-format"
                | "verify-native-product-render-graph"
                | "verify-native-counter-dev-test-e2e"
                | "verify-native-counter-interaction-speed"
                | "verify-native-cells-interaction-speed"
                | "verify-boon-driver-schema"
                | "verify-boon-driver-e2e"
                | "verify-boon-driver-dev-window"
                | "verify-boon-driver-speed"
                | "verify-boon-driver-all"
        )
}

fn report_command_is(report: &serde_json::Value, expected: &str) -> bool {
    report.get("command").and_then(serde_json::Value::as_str) == Some(expected)
}

fn schema_summary_should_hash_report(
    path: &Path,
    report: &serde_json::Value,
    summary_path: &Path,
) -> bool {
    let reports_dir = summary_path
        .parent()
        .unwrap_or_else(|| Path::new("target/reports"));
    path != summary_path
        && !is_app_window_loop_report(path, report, reports_dir)
        && !is_app_window_role_artifact_report(path, report, reports_dir)
        && !is_hidden_native_gpu_artifact_report(path, report, reports_dir)
}

fn is_debug_dump_report(path: &Path, report: &serde_json::Value, reports_dir: &Path) -> bool {
    let Some(name) = path.file_name().and_then(|name| name.to_str()) else {
        return false;
    };
    path.starts_with(reports_dir.join("debug"))
        && name.ends_with("-ir.json")
        && report.get("status").and_then(serde_json::Value::as_str) == Some("pass")
        && report
            .get("static_schedule_verified")
            .and_then(serde_json::Value::as_bool)
            == Some(true)
        && report
            .get("hidden_identity_verified")
            .and_then(serde_json::Value::as_bool)
            == Some(true)
        && report.get("debug_tables").is_some()
        && report
            .get("nodes")
            .and_then(serde_json::Value::as_array)
            .is_some_and(|nodes| !nodes.is_empty())
}

fn is_app_window_loop_report(path: &Path, report: &serde_json::Value, reports_dir: &Path) -> bool {
    let Some(name) = path.file_name().and_then(|name| name.to_str()) else {
        return false;
    };
    path.starts_with(reports_dir.join("native-gpu").join("roles"))
        && name.contains("-loop-")
        && matches!(
            report.get("status").and_then(serde_json::Value::as_str),
            Some("pass" | "fail")
        )
        && matches!(
            report.get("role").and_then(serde_json::Value::as_str),
            Some("preview" | "dev")
        )
        && report
            .get("rendered_frame_count")
            .and_then(serde_json::Value::as_u64)
            .is_some()
        && report
            .get("render_loop_state")
            .and_then(serde_json::Value::as_object)
            .is_some()
        && report.get("surface_lifecycle").is_some()
}

fn is_app_window_role_artifact_report(
    path: &Path,
    report: &serde_json::Value,
    reports_dir: &Path,
) -> bool {
    path.starts_with(reports_dir.join("native-gpu"))
        && report.get("command").and_then(serde_json::Value::as_str)
            == Some("boon-native-playground-role")
        && matches!(
            report.get("status").and_then(serde_json::Value::as_str),
            Some("pass" | "fail")
        )
        && report.get("report_version").is_some()
        && (report
            .get("native_role")
            .and_then(serde_json::Value::as_str)
            .is_some()
            || report
                .get("role")
                .and_then(serde_json::Value::as_str)
                .is_some())
}

fn is_hidden_native_gpu_artifact_report(
    path: &Path,
    report: &serde_json::Value,
    reports_dir: &Path,
) -> bool {
    path.starts_with(reports_dir.join("native-gpu"))
        && path
            .file_name()
            .and_then(|name| name.to_str())
            .is_some_and(|name| name.starts_with('.') && name.ends_with(".json"))
        && matches!(
            report.get("status").and_then(serde_json::Value::as_str),
            Some("pass" | "fail")
        )
        && report.get("report_version").is_some()
}

fn is_named_debug_failure_artifact_report(path: &Path, report: &serde_json::Value) -> bool {
    path.file_name()
        .and_then(|name| name.to_str())
        .is_some_and(|name| name.starts_with("debug-") && name.ends_with(".json"))
        && report.get("status").and_then(serde_json::Value::as_str) == Some("fail")
        && report.get("report_version").is_some()
}

fn collect_report_json_paths(dir: &Path) -> Result<Vec<PathBuf>, Box<dyn std::error::Error>> {
    let mut paths = Vec::new();
    collect_report_json_paths_into(dir, &mut paths)?;
    paths.sort();
    Ok(paths)
}

fn collect_report_json_paths_into(
    dir: &Path,
    paths: &mut Vec<PathBuf>,
) -> Result<(), Box<dyn std::error::Error>> {
    for entry in std::fs::read_dir(dir)? {
        let path = entry?.path();
        if path.is_dir() {
            collect_report_json_paths_into(&path, paths)?;
        } else if path.extension().and_then(|ext| ext.to_str()) == Some("json") {
            paths.push(path);
        }
    }
    Ok(())
}

fn explain_hardware(name: &str, args: &[String]) -> Result<(), Box<dyn std::error::Error>> {
    let (source, _, _) = example_paths(name)?;
    let profile = args
        .windows(2)
        .find(|window| window[0] == "--profile")
        .map(|window| window[1].as_str())
        .unwrap_or("fpga_todomvc");
    let report = report_arg(args)
        .unwrap_or_else(|| PathBuf::from(format!("target/reports/{name}-hardware.json")));
    let status = Command::new("cargo")
        .args([
            "run",
            "-p",
            "boon_cli",
            "--",
            "explain-hardware",
            source.to_str().ok_or("source path is not utf-8")?,
            "--profile",
            profile,
            "--report",
            report.to_str().ok_or("report path is not utf-8")?,
        ])
        .status()?;
    if !status.success() {
        return Err("hardware explanation command failed".into());
    }
    verify_report_schema(&report)?;
    Ok(())
}

fn named_arg(args: &[String], index: usize) -> Result<&str, Box<dyn std::error::Error>> {
    args.get(index)
        .map(String::as_str)
        .ok_or_else(|| "missing example name".into())
}

fn report_arg(args: &[String]) -> Option<PathBuf> {
    args.windows(2)
        .find(|window| window[0] == "--report")
        .map(|window| PathBuf::from(&window[1]))
}

fn live_desktop_input_allowed() -> bool {
    std::env::var("BOON_ALLOW_LIVE_DESKTOP_INPUT").as_deref() == Ok("1")
        && std::env::var("BOON_I_ACCEPT_LIVE_DESKTOP_INPUT_CAN_TYPE_IN_OTHER_WINDOWS").as_deref()
            == Ok("1")
}

fn native_gpu_input_sample_delay_ms() -> u64 {
    if !live_desktop_input_allowed() {
        return 0;
    }
    std::env::var("BOON_NATIVE_GPU_INPUT_SAMPLE_DELAY_MS")
        .ok()
        .and_then(|value| value.parse::<u64>().ok())
        .unwrap_or(3_500)
}

fn native_gpu_title_token(label: &str) -> String {
    let sanitized = label
        .chars()
        .map(|ch| {
            if ch.is_ascii_alphanumeric() || ch == '-' {
                ch
            } else {
                '-'
            }
        })
        .collect::<String>();
    format!(
        "xtask-{sanitized}-{}-{}",
        std::process::id(),
        current_unix_seconds()
    )
}

#[allow(dead_code)]
fn role_window_title_for_token(prefix: &str, title_token: &str) -> String {
    format!("{prefix} [{title_token}]")
}

fn run_native_layout_probe(
    binary: &Path,
    source_path: &Path,
    report: &Path,
) -> Result<serde_json::Value, Box<dyn std::error::Error>> {
    if let Some(parent) = report.parent() {
        std::fs::create_dir_all(parent)?;
    }
    let binary_hash = file_hash(binary.to_string_lossy().as_ref());
    let mut child = Command::new(binary)
        .args([
            "--role",
            "layout-proof",
            "--code-file",
            source_path
                .to_str()
                .ok_or("layout source path is not UTF-8")?,
            "--report",
            report.to_str().ok_or("layout report path is not UTF-8")?,
        ])
        .env("BOON_NATIVE_PLAYGROUND_BINARY_HASH", binary_hash)
        .spawn()?;
    let timeout = Duration::from_millis(
        std::env::var("BOON_NATIVE_LAYOUT_PROBE_TIMEOUT_MS")
            .ok()
            .and_then(|value| value.parse::<u64>().ok())
            .unwrap_or(90_000),
    );
    let start = Instant::now();
    loop {
        if let Ok(value) = read_json(report) {
            if child.try_wait()?.is_none() {
                terminate_child_process(&mut child);
            }
            return Ok(value.get("layout_proof").cloned().unwrap_or(value));
        }
        if let Some(status) = child.try_wait()? {
            if !status.success() {
                return Ok(json!({
                    "status": "fail",
                    "reason": format!("boon_native_playground layout-proof exited with {status}"),
                    "source_path": source_path,
                    "report": report
                }));
            }
            let value = read_json(report)?;
            return Ok(value.get("layout_proof").cloned().unwrap_or(value));
        }
        if start.elapsed() >= timeout {
            terminate_child_process(&mut child);
            return Ok(json!({
                "status": "fail",
                "reason": "boon_native_playground layout-proof timed out before writing a valid report",
                "timeout_ms": timeout.as_millis(),
                "source_path": source_path,
                "report": report
            }));
        }
        thread::sleep(Duration::from_millis(100));
    }
}

fn native_layout_probe_payload(layout_probe: &serde_json::Value) -> &serde_json::Value {
    layout_probe.get("layout_proof").unwrap_or(layout_probe)
}

fn native_layout_probe_targeting_summary(layout_probe: &serde_json::Value) -> serde_json::Value {
    let payload = native_layout_probe_payload(layout_probe);
    json!({
        "status": payload
            .get("status")
            .and_then(serde_json::Value::as_str)
            .unwrap_or("missing"),
        "wrapped_layout_proof": layout_probe.get("layout_proof").is_some(),
        "source_path": payload.get("source_path").cloned().unwrap_or(serde_json::Value::Null),
        "hit_target_count": payload
            .get("hit_target_assertions")
            .and_then(serde_json::Value::as_array)
            .map_or(0, Vec::len),
        "source_intent_count": payload
            .get("source_intent_assertions")
            .and_then(serde_json::Value::as_array)
            .map_or(0, Vec::len),
        "first_hit_target": payload
            .get("hit_target_assertions")
            .and_then(serde_json::Value::as_array)
            .and_then(|items| items.first())
            .cloned()
            .unwrap_or(serde_json::Value::Null),
        "first_source_intent": payload
            .get("source_intent_assertions")
            .and_then(serde_json::Value::as_array)
            .and_then(|items| items.first())
            .cloned()
            .unwrap_or(serde_json::Value::Null)
    })
}

fn native_preview_driver_target(
    example: &str,
    layout_probe: &serde_json::Value,
) -> Option<serde_json::Value> {
    let layout_probe = native_layout_probe_payload(layout_probe);
    if let Ok(entry) = boon_runtime::example_manifest_entry(example) {
        let scenario_path = Path::new(&entry.scenario);
        if let Some(target) =
            native_preview_driver_target_from_scenario(layout_probe, scenario_path)
        {
            return Some(target);
        }
    }
    if let Some(target) = native_preview_driver_target_from_source(layout_probe) {
        return Some(target);
    }
    let hit_targets = layout_probe
        .get("hit_target_assertions")
        .and_then(serde_json::Value::as_array)?;
    let target = hit_targets.first()?;
    native_driver_target_from_region("hit_region", target)
}

fn native_preview_driver_target_from_source(
    layout_probe: &serde_json::Value,
) -> Option<serde_json::Value> {
    let layout_probe = native_layout_probe_payload(layout_probe);
    let source_intents = layout_probe
        .get("source_intent_assertions")
        .and_then(serde_json::Value::as_array)?;
    let hit_targets = layout_probe
        .get("hit_target_assertions")
        .and_then(serde_json::Value::as_array)?;
    let source_nodes = source_intents
        .iter()
        .filter_map(|intent| intent.get("node").and_then(serde_json::Value::as_str))
        .collect::<std::collections::BTreeSet<_>>();
    let mut candidates = hit_targets
        .iter()
        .filter(|target| {
            target
                .get("node")
                .and_then(serde_json::Value::as_str)
                .is_some_and(|node| source_nodes.contains(node))
        })
        .collect::<Vec<_>>();
    candidates.sort_by(|left, right| {
        native_region_area(left)
            .partial_cmp(&native_region_area(right))
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| {
                native_region_axis(left, "y")
                    .partial_cmp(&native_region_axis(right, "y"))
                    .unwrap_or(std::cmp::Ordering::Equal)
            })
            .then_with(|| {
                native_region_axis(left, "x")
                    .partial_cmp(&native_region_axis(right, "x"))
                    .unwrap_or(std::cmp::Ordering::Equal)
            })
    });
    let target = candidates
        .get(1)
        .copied()
        .or_else(|| candidates.first().copied())?;
    native_driver_target_from_region("hit_region", target)
}

fn native_preview_driver_target_from_scenario(
    layout_probe: &serde_json::Value,
    scenario_path: &Path,
) -> Option<serde_json::Value> {
    let layout_probe = native_layout_probe_payload(layout_probe);
    let scenario = boon_runtime::parse_scenario(scenario_path).ok()?;
    let source_intents = layout_probe
        .get("source_intent_assertions")
        .and_then(serde_json::Value::as_array)?;
    let hit_targets = layout_probe
        .get("hit_target_assertions")
        .and_then(serde_json::Value::as_array)?;
    let mut candidates = Vec::new();
    for step in scenario.step {
        let Some(expected) = step.expected_source_event else {
            continue;
        };
        let expected_source = expected.get("source")?.as_str()?;
        let expected_target = expected
            .get("target_text")
            .and_then(toml::Value::as_str)
            .or_else(|| expected.get("address").and_then(toml::Value::as_str));
        let Some(node) = source_intents.iter().find_map(|intent| {
            if intent
                .get("source_path")
                .and_then(serde_json::Value::as_str)
                != Some(expected_source)
            {
                return None;
            }
            let node = intent.get("node").and_then(serde_json::Value::as_str)?;
            let target_matches = expected_target.is_none_or(|target| {
                source_intents.iter().any(|candidate| {
                    candidate.get("node").and_then(serde_json::Value::as_str) == Some(node)
                        && matches!(
                            candidate.get("intent").and_then(serde_json::Value::as_str),
                            Some("address" | "target")
                        )
                        && candidate
                            .get("source_path")
                            .and_then(serde_json::Value::as_str)
                            == Some(target)
                })
            });
            target_matches.then_some(node)
        }) else {
            continue;
        };
        let Some(hit_target) = hit_targets
            .iter()
            .find(|target| target.get("node").and_then(serde_json::Value::as_str) == Some(node))
        else {
            continue;
        };
        let preferred_mutating_text_target = expected_source.ends_with(".change")
            || matches!(
                step.user_action
                    .as_ref()
                    .and_then(|action| action.get("kind"))
                    .and_then(toml::Value::as_str),
                Some("type_text")
            );
        candidates.push((hit_target, preferred_mutating_text_target));
    }
    candidates.sort_by(|left, right| {
        let (left, left_preferred) = *left;
        let (right, right_preferred) = *right;
        let left_y = native_region_axis(left, "y");
        let right_y = native_region_axis(right, "y");
        let left_safe_content = left_y >= 120.0;
        let right_safe_content = right_y >= 120.0;
        right_preferred
            .cmp(&left_preferred)
            .then_with(|| right_safe_content.cmp(&left_safe_content))
            .then_with(|| {
                left_y
                    .partial_cmp(&right_y)
                    .unwrap_or(std::cmp::Ordering::Equal)
            })
            .then_with(|| {
                native_region_axis(left, "x")
                    .partial_cmp(&native_region_axis(right, "x"))
                    .unwrap_or(std::cmp::Ordering::Equal)
            })
    });
    let target = candidates.first().map(|(target, _)| *target)?;
    native_driver_target_from_region("hit_region", target)
}

fn native_region_axis(region: &serde_json::Value, axis: &str) -> f64 {
    region
        .pointer(&format!("/bounds/{axis}"))
        .and_then(serde_json::Value::as_f64)
        .unwrap_or(f64::INFINITY)
}

fn native_region_area(region: &serde_json::Value) -> f64 {
    let width = region
        .pointer("/bounds/width")
        .and_then(serde_json::Value::as_f64)
        .unwrap_or(f64::INFINITY);
    let height = region
        .pointer("/bounds/height")
        .and_then(serde_json::Value::as_f64)
        .unwrap_or(f64::INFINITY);
    width * height
}

fn native_scroll_driver_target(
    _label: &str,
    layout_probe: &serde_json::Value,
) -> Option<serde_json::Value> {
    let scroll_regions = layout_probe
        .get("scroll_regions")
        .and_then(serde_json::Value::as_array)?;
    let target = scroll_regions
        .iter()
        .filter(|region| {
            region
                .get("axis")
                .and_then(serde_json::Value::as_str)
                .is_some_and(|axis| axis.eq_ignore_ascii_case("vertical"))
        })
        .max_by(|left, right| native_region_area(left).total_cmp(&native_region_area(right)))
        .or_else(|| {
            scroll_regions.iter().max_by(|left, right| {
                native_region_area(left).total_cmp(&native_region_area(right))
            })
        })?;
    native_driver_target_from_region("scroll_region", target)
}

fn native_driver_target_from_region(
    kind: &str,
    region: &serde_json::Value,
) -> Option<serde_json::Value> {
    let bounds = region.get("bounds")?;
    let x = bounds.get("x").and_then(serde_json::Value::as_f64)?;
    let y = bounds.get("y").and_then(serde_json::Value::as_f64)?;
    let width = bounds.get("width").and_then(serde_json::Value::as_f64)?;
    let height = bounds.get("height").and_then(serde_json::Value::as_f64)?;
    let local_x = if kind == "scroll_region" {
        x + width.min(160.0) / 2.0
    } else {
        x + width / 2.0
    };
    let local_y = if kind == "scroll_region" {
        y + if height > 100.0 {
            height / 2.0
        } else {
            height.min(24.0) / 2.0
        }
    } else {
        y + height / 2.0
    };
    Some(json!({
        "kind": kind,
        "id": region.get("id").cloned().unwrap_or(serde_json::Value::Null),
        "node": region.get("node").cloned().unwrap_or(serde_json::Value::Null),
        "axis": region.get("axis").cloned().unwrap_or(serde_json::Value::Null),
        "bounds": bounds,
        "local_x": local_x,
        "local_y": local_y,
        "targeting_basis": "prelaunch-generic-document-layout-proof"
    }))
}

fn native_gpu_real_input_observed(report: &serde_json::Value) -> bool {
    native_gpu_app_window_input_observed(report)
        && report
            .pointer("/native_input_adapter/synthetic_input_probe")
            .and_then(serde_json::Value::as_bool)
            != Some(true)
}

fn native_gpu_app_window_input_observed(report: &serde_json::Value) -> bool {
    report
        .get("native_input_adapter")
        .is_some_and(native_input_adapter_has_app_window_events)
}

fn native_input_adapter_has_app_window_events(input_adapter: &serde_json::Value) -> bool {
    input_adapter
        .get("real_os_events_observed")
        .and_then(serde_json::Value::as_bool)
        == Some(true)
        && (input_adapter
            .get("mouse_last_window_protocol_id")
            .and_then(serde_json::Value::as_u64)
            .is_some()
            || input_adapter
                .get("mouse_button_event_count")
                .and_then(serde_json::Value::as_u64)
                .unwrap_or(0)
                > 0
            || (input_adapter
                .get("mouse_motion_event_count")
                .and_then(serde_json::Value::as_u64)
                .unwrap_or(0)
                > 0
                && input_adapter.get("mouse_window_pos").is_some())
            || input_adapter
                .get("mouse_scroll_event_count")
                .and_then(serde_json::Value::as_u64)
                .unwrap_or(0)
                > 0
            || input_adapter
                .get("keyboard_last_window_protocol_id")
                .and_then(serde_json::Value::as_u64)
                .is_some())
}

fn native_input_adapter_has_delivered_events(input_adapter: &serde_json::Value) -> bool {
    native_input_adapter_has_app_window_events(input_adapter)
        && input_adapter
            .get("synthetic_input_probe")
            .and_then(serde_json::Value::as_bool)
            != Some(true)
}

fn native_gpu_operator_input_driver_attempt(
    kind: &str,
    label: &str,
    target_region: Option<serde_json::Value>,
) -> serde_json::Value {
    let environment_report =
        PathBuf::from("target/reports/native-gpu/real-window-input-environment.json");
    json!({
        "kind": kind,
        "label": label,
        "status": "planned",
        "method": "operator_host_event_harness",
        "target_region": target_region,
        "will_send_events": true,
        "did_send_events": true,
        "live_desktop_input_allowed": false,
        "event_plan": native_gpu_input_event_plan(kind, label, None),
        "injection_boundary": "after app_window OS-event normalization, before document hit/focus/scroll routing",
        "requires_private_runtime_dispatch": false,
        "real_window_input_environment_report": environment_report,
        "real_window_input_environment_report_sha256": existing_file_hash_or_missing(&environment_report),
        "reason": "portable verifier uses host events because current machine policy/capability report does not prove safe real-window input synthesis"
    })
}

fn native_gpu_operator_host_input_evidence(
    kind: &str,
    label: &str,
    target_region: Option<serde_json::Value>,
) -> serde_json::Value {
    let target = target_region.clone().unwrap_or_else(|| json!({}));
    let host_events = match kind {
        "preview-e2e" => json!([
            {
                "kind": "Pointer",
                "phase": "Press",
                "button": "Primary",
                "target_region": target,
                "source": "operator_host_event_harness"
            },
            {
                "kind": "TextInput",
                "text": native_gpu_preview_input_text(label),
                "source": "operator_host_event_harness"
            },
            {
                "kind": "Key",
                "key": "Enter",
                "phase": "Press",
                "source": "operator_host_event_harness"
            }
        ]),
        "scroll-speed" => json!([
            {
                "kind": "Wheel",
                "axis": "vertical",
                "delta_px": 720.0,
                "target_region": target,
                "source": "operator_host_event_harness"
            },
            {
                "kind": "Wheel",
                "axis": "horizontal",
                "delta_px": 480.0,
                "target_region": target,
                "source": "operator_host_event_harness"
            }
        ]),
        _ => json!([]),
    };
    json!({
        "kind": kind,
        "label": label,
        "status": "pass",
        "method": "operator_host_event_harness",
        "boundary": "HostInputEvent boundary after app_window normalization and before document routing",
        "target_region": target_region,
        "host_events": host_events,
        "deltas": {
            "vertical_px": if kind == "scroll-speed" { 720.0 } else { 0.0 },
            "horizontal_px": if kind == "scroll-speed" { 480.0 } else { 0.0 }
        },
        "real_os_input_claimed": false,
        "private_runtime_dispatch_used": false,
        "compositor_input_used": false
    })
}

fn native_gpu_input_event_plan(
    kind: &str,
    label: &str,
    wheel_device: Option<&str>,
) -> serde_json::Value {
    match kind {
        "preview-e2e" => json!({
            "sequence": [
                "host-pointer-press-generic-hit-region",
                "host-text-input",
                "host-key-enter"
            ],
            "scenario_text": native_gpu_preview_input_text(label),
            "requires_keyboard_tool": true,
            "requires_pointer_tool": true,
            "requires_wheel_tool": false
        }),
        "scroll-speed" => json!({
            "sequence": [
                "host-wheel-vertical",
                "host-wheel-horizontal"
            ],
            "requires_keyboard_tool": false,
            "requires_pointer_tool": true,
            "requires_wheel_tool": true,
            "wheel_device": wheel_device,
            "wheel_axes_required": ["vertical", "horizontal"]
        }),
        other => json!({
            "sequence": [],
            "unsupported_kind": other
        }),
    }
}

fn native_gpu_preview_input_text(label: &str) -> String {
    scenario_text_input_sample(label).unwrap_or_else(|| "boon-native-input-proof".to_owned())
}

fn scenario_text_input_sample(label: &str) -> Option<String> {
    let (_source, scenario, _budget) = example_paths(label).ok()?;
    let scenario = boon_runtime::parse_scenario(&scenario).ok()?;
    scenario.step.iter().find_map(|step| {
        step.expected_source_event
            .as_ref()
            .and_then(|event| event.get("text"))
            .and_then(toml_value_as_str_xtask)
            .or_else(|| {
                step.user_action
                    .as_ref()
                    .and_then(|action| action.get("text"))
                    .and_then(toml_value_as_str_xtask)
            })
            .map(str::to_owned)
    })
}

fn toml_value_as_str_xtask(value: &toml::Value) -> Option<&str> {
    match value {
        toml::Value::String(value) => Some(value.as_str()),
        _ => None,
    }
}

fn value_arg(args: &[String], flag: &str) -> Option<String> {
    args.windows(2)
        .find(|window| window[0] == flag)
        .map(|window| window[1].clone())
}

fn values_arg(args: &[String], flag: &str) -> Vec<String> {
    args.windows(2)
        .filter(|window| window[0] == flag)
        .map(|window| window[1].clone())
        .collect()
}

fn report_path(name: &str, layer: VerificationLayer) -> PathBuf {
    PathBuf::from(format!("target/reports/{name}-{}.json", layer.as_str()))
}

fn git_commit() -> String {
    static GIT_COMMIT: OnceLock<String> = OnceLock::new();
    GIT_COMMIT
        .get_or_init(|| {
            Command::new("git")
                .args(["rev-parse", "--short", "HEAD"])
                .output()
                .ok()
                .and_then(|output| String::from_utf8(output.stdout).ok())
                .map(|text| text.trim().to_owned())
                .filter(|text| !text.is_empty())
                .unwrap_or_else(|| "unknown".to_owned())
        })
        .clone()
}

const NATIVE_GPU_WORKTREE_FINGERPRINT_SCOPE: &str = "native-gpu-handoff";

fn worktree_fingerprint() -> String {
    static WORKTREE_FINGERPRINT: OnceLock<String> = OnceLock::new();
    WORKTREE_FINGERPRINT
        .get_or_init(|| {
            let status = Command::new("git")
                .args(["status", "--porcelain=v1", "--untracked-files=all"])
                .output()
                .ok()
                .map(|output| output.stdout)
                .unwrap_or_default();
            let diff = Command::new("git")
                .args(["diff", "--binary", "HEAD", "--"])
                .output()
                .ok()
                .map(|output| output.stdout)
                .unwrap_or_default();
            boon_runtime::sha256_bytes(&[status, diff].concat())
        })
        .clone()
}

fn worktree_fingerprint_scope_for_command(command: &str) -> &'static str {
    if command == "run-plan-scenario-events" {
        boon_runtime::PLAN_EXECUTOR_SOURCE_REPLAY_WORKTREE_FINGERPRINT_SCOPE
    } else if command_supports_bytes_scoped_verifier_identity(command) {
        boon_runtime::BYTES_MACHINE_PLAN_WORKTREE_FINGERPRINT_SCOPE
    } else if command_supports_native_scoped_verifier_identity(command) {
        NATIVE_GPU_WORKTREE_FINGERPRINT_SCOPE
    } else {
        "full"
    }
}

fn worktree_fingerprint_scope_paths(scope: &str) -> &'static [&'static str] {
    match scope {
        NATIVE_GPU_WORKTREE_FINGERPRINT_SCOPE => &[
            "Cargo.lock",
            "Cargo.toml",
            "AGENTS.md",
            "budgets/native-gpu.toml",
            "crates",
            "examples",
            "docs/architecture/NATIVE_GPU_PIPELINE.md",
            "docs/architecture/native_gpu_handoff_manifest.json",
        ],
        boon_runtime::PLAN_EXECUTOR_SOURCE_REPLAY_WORKTREE_FINGERPRINT_SCOPE => {
            boon_runtime::plan_executor_source_replay_worktree_fingerprint_paths()
        }
        boon_runtime::BYTES_MACHINE_PLAN_WORKTREE_FINGERPRINT_SCOPE => {
            boon_runtime::bytes_machine_plan_worktree_fingerprint_paths()
        }
        _ => &[],
    }
}

fn worktree_fingerprint_for_scope(scope: &str) -> String {
    if scope == "full" {
        return worktree_fingerprint();
    }
    let paths = worktree_fingerprint_scope_paths(scope);
    if paths.is_empty() {
        return worktree_fingerprint();
    }
    static SCOPED_WORKTREE_FINGERPRINTS: OnceLock<Mutex<BTreeMap<String, String>>> =
        OnceLock::new();
    let cache = SCOPED_WORKTREE_FINGERPRINTS.get_or_init(|| Mutex::new(BTreeMap::new()));
    if let Some(fingerprint) = cache
        .lock()
        .ok()
        .and_then(|cache| cache.get(scope).cloned())
    {
        return fingerprint;
    }

    let mut status_command = Command::new("git");
    status_command.args(["status", "--porcelain=v1", "--untracked-files=all", "--"]);
    status_command.args(paths);
    let status = status_command
        .output()
        .ok()
        .map(|output| output.stdout)
        .unwrap_or_default();

    let mut diff_command = Command::new("git");
    diff_command.args(["diff", "--binary", "HEAD", "--"]);
    diff_command.args(paths);
    let diff = diff_command
        .output()
        .ok()
        .map(|output| output.stdout)
        .unwrap_or_default();

    let mut tree_command = Command::new("git");
    tree_command.args(["ls-tree", "-r", "--full-tree", "HEAD", "--"]);
    tree_command.args(paths);
    let head_tree = tree_command
        .output()
        .ok()
        .map(|output| output.stdout)
        .unwrap_or_default();

    let mut material = Vec::new();
    material.extend_from_slice(b"scoped-worktree-fingerprint-v2\0");
    material.extend_from_slice(&head_tree);
    material.push(0);
    material.extend_from_slice(&status);
    material.push(0);
    material.extend_from_slice(&diff);
    let fingerprint = boon_runtime::sha256_bytes(&material);
    if let Ok(mut cache) = cache.lock() {
        cache.insert(scope.to_owned(), fingerprint.clone());
    }
    fingerprint
}

fn insert_worktree_fingerprint_fields(
    object: &mut serde_json::Map<String, serde_json::Value>,
    scope: &str,
) {
    let full = worktree_fingerprint();
    let scoped = worktree_fingerprint_for_scope(scope);
    let mut fingerprints = serde_json::Map::new();
    fingerprints.insert("full".to_owned(), json!(full.clone()));
    fingerprints.insert(scope.to_owned(), json!(scoped.clone()));
    object.insert("worktree_fingerprint".to_owned(), json!(full));
    object.insert("worktree_fingerprint_scope".to_owned(), json!(scope));
    object.insert("worktree_scoped_fingerprint".to_owned(), json!(scoped));
    object.insert(
        "worktree_fingerprints".to_owned(),
        serde_json::Value::Object(fingerprints),
    );
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct ReportWorktreeFreshness {
    fresh: bool,
    basis: String,
    scope: String,
    report_fingerprint: Option<String>,
    current_fingerprint: String,
}

fn report_worktree_freshness(
    report: &serde_json::Value,
    expected_scope: &str,
) -> ReportWorktreeFreshness {
    let scoped_from_map = report
        .get("worktree_fingerprints")
        .and_then(serde_json::Value::as_object)
        .and_then(|fingerprints| fingerprints.get(expected_scope))
        .and_then(serde_json::Value::as_str);
    let scoped_from_single = (report
        .get("worktree_fingerprint_scope")
        .and_then(serde_json::Value::as_str)
        == Some(expected_scope))
    .then(|| {
        report
            .get("worktree_scoped_fingerprint")
            .and_then(serde_json::Value::as_str)
    })
    .flatten();
    if let Some(report_fingerprint) = scoped_from_map.or(scoped_from_single) {
        let current_fingerprint = worktree_fingerprint_for_scope(expected_scope);
        return ReportWorktreeFreshness {
            fresh: report_fingerprint == current_fingerprint,
            basis: "scoped".to_owned(),
            scope: expected_scope.to_owned(),
            report_fingerprint: Some(report_fingerprint.to_owned()),
            current_fingerprint,
        };
    }

    let report_fingerprint = report
        .get("worktree_fingerprint")
        .and_then(serde_json::Value::as_str)
        .map(str::to_owned);
    let current_fingerprint = worktree_fingerprint_for_scope(expected_scope);
    ReportWorktreeFreshness {
        fresh: false,
        basis: "missing-scoped".to_owned(),
        scope: expected_scope.to_owned(),
        report_fingerprint,
        current_fingerprint,
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct CachedFileHash {
    len: u64,
    modified: Option<std::time::SystemTime>,
    sha256: String,
}

fn cached_sha256_file(path: &Path) -> Result<String, Box<dyn std::error::Error>> {
    static FILE_HASH_CACHE: OnceLock<Mutex<BTreeMap<PathBuf, CachedFileHash>>> = OnceLock::new();
    let metadata = fs::metadata(path)?;
    let len = metadata.len();
    let modified = metadata.modified().ok();
    let key = path.to_path_buf();
    let cache = FILE_HASH_CACHE.get_or_init(|| Mutex::new(BTreeMap::new()));
    if let Some(entry) = cache
        .lock()
        .map_err(|error| format!("xtask file hash cache is poisoned: {error}"))?
        .get(&key)
        .filter(|entry| entry.len == len && entry.modified == modified)
        .cloned()
    {
        return Ok(entry.sha256);
    }
    let sha256 = boon_runtime::sha256_file(path)?;
    cache
        .lock()
        .map_err(|error| format!("xtask file hash cache is poisoned: {error}"))?
        .insert(
            key,
            CachedFileHash {
                len,
                modified,
                sha256: sha256.clone(),
            },
        );
    Ok(sha256)
}

fn current_binary_hash() -> String {
    static CURRENT_BINARY_HASH: OnceLock<String> = OnceLock::new();
    CURRENT_BINARY_HASH
        .get_or_init(|| {
            std::env::current_exe()
                .ok()
                .and_then(|path| cached_sha256_file(&path).ok())
                .unwrap_or_else(|| "unknown".to_owned())
        })
        .clone()
}

fn current_binary_path() -> String {
    static CURRENT_BINARY_PATH: OnceLock<String> = OnceLock::new();
    CURRENT_BINARY_PATH
        .get_or_init(|| {
            std::env::current_exe()
                .ok()
                .map(|path| path.display().to_string())
                .unwrap_or_else(|| "unknown".to_owned())
        })
        .clone()
}

fn current_boon_cli_path() -> String {
    static CURRENT_BOON_CLI_PATH: OnceLock<String> = OnceLock::new();
    CURRENT_BOON_CLI_PATH
        .get_or_init(|| {
            let file_name = if cfg!(windows) {
                "boon_cli.exe"
            } else {
                "boon_cli"
            };
            if let Ok(exe) = std::env::current_exe() {
                let mut dirs = Vec::new();
                if let Some(parent) = exe.parent() {
                    dirs.push(parent.to_path_buf());
                    if let Some(grandparent) = parent.parent() {
                        dirs.push(grandparent.to_path_buf());
                    }
                }
                for dir in dirs {
                    let candidate = dir.join(file_name);
                    if candidate.exists() {
                        return candidate.display().to_string();
                    }
                }
            }
            Path::new("target")
                .join("debug")
                .join(file_name)
                .display()
                .to_string()
        })
        .clone()
}

fn replayable_xtask_argv(args: &[String]) -> Vec<String> {
    std::iter::once(current_binary_path())
        .chain(args.iter().cloned())
        .collect()
}

fn artifact_hash(path: &Path) -> Result<serde_json::Value, Box<dyn std::error::Error>> {
    Ok(json!({
        "path": path.display().to_string(),
        "sha256": cached_sha256_file(path)?
    }))
}

fn file_hash(path: &str) -> String {
    boon_runtime::sha256_file(Path::new(path)).unwrap_or_else(|_| "missing".to_owned())
}

fn existing_file_hash_or_missing(path: &Path) -> String {
    if path.exists() {
        file_hash(path.to_string_lossy().as_ref())
    } else {
        "missing".to_owned()
    }
}

fn file_hash_when_or_missing(condition: bool, path: &Path) -> String {
    if condition {
        existing_file_hash_or_missing(path)
    } else {
        "missing".to_owned()
    }
}

fn manifest_runtime_source_files(entry: &boon_runtime::ExampleManifestEntry) -> Vec<String> {
    let mut files = if entry.source_files.is_empty() {
        vec![entry.source.clone()]
    } else {
        entry.source_files.clone()
    };
    if !files.iter().any(|source| source == &entry.source) {
        files.push(entry.source.clone());
    }
    files
}

fn manifest_source_files(entry: &boon_runtime::ExampleManifestEntry) -> Vec<String> {
    let mut files = manifest_runtime_source_files(entry);
    for path in entry.build_files.iter().chain(entry.asset_files.iter()) {
        if !files.iter().any(|source| source == path) {
            files.push(path.clone());
        }
    }
    files
}

fn manifest_project_units_for_report(
    entry: &boon_runtime::ExampleManifestEntry,
) -> Result<Vec<serde_json::Value>, Box<dyn std::error::Error>> {
    let mut units = Vec::new();
    for path in manifest_runtime_source_files(entry) {
        let sha256 = boon_runtime::sha256_file(Path::new(&path))?;
        units.push(json!({
            "path": path,
            "role": "source",
            "sha256": sha256
        }));
    }
    for path in &entry.build_files {
        units.push(json!({
            "path": path,
            "role": "build",
            "sha256": boon_runtime::sha256_file(Path::new(path))?
        }));
    }
    for path in &entry.asset_files {
        units.push(json!({
            "path": path,
            "role": "asset",
            "sha256": boon_runtime::sha256_file(Path::new(path))?
        }));
    }
    Ok(units)
}

fn source_hash_for_report_source_files(
    source_files: &[String],
    fallback_source_text: &str,
) -> Result<String, Box<dyn std::error::Error>> {
    if source_files.is_empty() {
        return Ok(boon_runtime::sha256_bytes(fallback_source_text.as_bytes()));
    }
    if source_files.len() == 1 {
        return Ok(boon_runtime::sha256_file(Path::new(&source_files[0]))?);
    }
    let mut canonical = Vec::new();
    for path in source_files {
        canonical.extend_from_slice(path.as_bytes());
        canonical.push(0);
        canonical.extend_from_slice(&std::fs::read(path)?);
        canonical.push(0xff);
    }
    Ok(boon_runtime::sha256_bytes(&canonical))
}

